import{_ as a,o as t,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Web Advanced Features","description":"","frontmatter":{"title":"Web Advanced Features","slug":"web-advanced-features"},"headers":[],"relativePath":"developer-hub/web-advanced-features.md","filePath":"developer-hub/web-advanced-features.md"}'),o={name:"developer-hub/web-advanced-features.md"};function i(r,e,d,l,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch Web SDK exposes a set of methods specifically made for websites, which you can call using JavaScript.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you get started implementing the features on this page, you first need to:</p><ol><li>Create an account in the <a href="./web-basic-integration.html#1-configure-branch">Branch Dashboard</a>.</li><li><a href="./web-basic-integration.html#2-initialize-branch">Integrate</a> the Branch Web SDK into your web app.</li><li><a href="./web-basic-integration.html#4-validate-integration">Validate</a> your Branch Web SDK integration.</li></ol><h2 id="web-sdk-fields" tabindex="-1">Web SDK fields <a class="header-anchor" href="#web-sdk-fields" aria-label="Permalink to &quot;Web SDK fields&quot;">​</a></h2><p>The Branch Web SDK provides relevant information about end-users and linking using the following fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>identity_id</code></td><td>A Branch generated identity ID, unique to the customer. Used for attribution and Branch matching that facilitates deep linking.</td><td><code>identity_id=759504944901509572</code></td></tr><tr><td><code>sdk</code></td><td>The Branch Web SDK version that was loaded on the webpage.</td><td><code>sdk=web2.52.5</code></td></tr><tr><td><code>session_id</code></td><td>A unique ID generated by Branch for the session. Used for attribution and Branch matching that facilitates deep linking.</td><td><code>session_id=759504944919560999</code></td></tr><tr><td><code>browser_fingerprint_id</code></td><td>A unique ID generated by Branch for the end user&#39;s browser. Used for attribution and Branch matching that facilitates deep linking.</td><td><code>browser_fingerprint_id=596017357522557131</code></td></tr><tr><td><code>alternative_browser_fingerprint_id</code></td><td>A unique ID generated by Branch for the end user&#39;s browser. This is created as a fallback to <code>browser_fingerprint_id</code>.</td><td><code>alternate_browser_fingerprint_id=596017357522557245</code></td></tr><tr><td><code>link_identifier</code></td><td>A unique ID generated by Branch for a Branch Link click. This is set when a user is referred to the site from a Branch Link.</td><td><code>link_identifier=&quot;348527481794276288&quot;</code></td></tr><tr><td><code>options</code></td><td>The Branch SDK <a href="./web-basic-integration.html#example-with-additional-options">initialization options</a>.</td><td><code>options={no_journeys:true};</code></td></tr><tr><td><code>initial_referrer</code></td><td>Referral URL that led to the current page where the Branch Web SDK logged web session start. Specified by the client.</td><td><code>&quot;initial_referrer=https://www.google.com/&quot;</code></td></tr><tr><td><code>tracking_disabled</code></td><td>Disables tracking of users by Branch.</td><td><code>tracking_disabled=true</code></td></tr><tr><td><code>current_url</code></td><td>The URL where the Branch Web SDK is initialized.</td><td><code>current_url=&quot;https://www.example.com&quot;</code></td></tr><tr><td><code>ip_address</code></td><td>End user&#39;s device IP address.</td><td><code>ip_address=192.158.1.38</code></td></tr><tr><td><code>screen_height</code></td><td>End user&#39;s device screen height.</td><td><code>screen_height=1080</code></td></tr><tr><td><code>screen_width</code></td><td>End user&#39;s device screen width.</td><td><code>screen_width=1920</code></td></tr><tr><td><code>window_device_pixel_ratio</code></td><td>End user&#39;s device pixel ratio.</td><td><code>window_device_pixel_ratio=1</code></td></tr><tr><td><code>_t</code></td><td>Shorthand for <code>browser_fingerprint_id</code>.</td><td><code>_t=596017357522557131</code></td></tr><tr><td><code>branch_key</code></td><td>The Branch Key used to initialize the Branch Web SDK. Available in the <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Branch Dashboard</a>.</td><td><code>branch_key=key_live_00000000000</code></td></tr><tr><td><code>identity</code></td><td>Custom identity for the end user set by you.</td><td><code>identity=&quot;unique-user-identity-452q389031&quot;</code></td></tr><tr><td><code>instrumentation</code></td><td>Branch Web SDK performance metrics.</td><td></td></tr><tr><td><code>event</code></td><td>Name of the Branch Event that initialized the Branch Web SDK. Values can be <code>web_session_start</code> or <code>pageview</code>.</td><td><code>event=pageview</code></td></tr><tr><td><code>metadata</code></td><td>Custom metadata sent by you at the time of Branch initialization.</td><td><code>metadata={ &quot;url&quot;:&quot;https://github.com/BranchMetrics/web-branch-deep-linking-attribution&quot;, &quot;user_agent&quot;:&quot;Mozilla/5.0 (Macintosh; Intel Mac OS X 10_14_6) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/79.0.3945.130 Safari/537.36&quot;, &quot;language&quot;:&quot;en-US&quot;, &quot;screen_width&quot;:3008, &quot;screen_height&quot;:1692, &quot;window_device_pixel_ratio&quot;:2, &quot;og_data&quot;:{ &quot;$og_title&quot;:&quot;Branch Metrics Web SDK Example App&quot;, &quot;$og_description&quot;:&quot;A basic example of the Branch Web SDK.&quot;, &quot;$og_image_url&quot;:&quot;</code></td></tr><tr><td><code>no_journeys</code></td><td>Whether Branch Journeys should show on the page where the Branch Web SDK was initialized. Default is <code>false</code>.</td><td><code>no_journeys=true</code></td></tr><tr><td><code>user_language</code></td><td>End user browser&#39;s language code.</td><td><code>user_language=en-US</code></td></tr><tr><td><code>has_app_websdk</code></td><td>Probabilistic boolean flag indicating whether the end user has the app installed or not.</td><td><code>has_app_websdk=false</code></td></tr><tr><td><code>source</code></td><td>Which Branch SDK initialized the web session.</td><td><code>source=web-sdk</code></td></tr><tr><td><code>feature</code></td><td>Analytics tag set at the time of Branch Web SDK initialization, if applicable.</td><td><code>feature=journeys</code></td></tr><tr><td><code>is_iframe</code></td><td>Boolean indicating whether the Branch Web SDK is in an iframe.</td><td><code>is_iframe=false</code></td></tr><tr><td><code>data</code></td><td>Branch Deep Link data, if the end user was redirected from a Branch Deep Link.</td><td><code>data= {&quot;$canonical_url&quot;:&quot;https://github.com/BranchMetrics/web-branch-deep-linking-attribution&quot;, &quot;$og_title&quot;:&quot;Branch Metrics Web SDK Example App&quot;, &quot;$og_description&quot;:&quot;A basic example of the Branch Web SDK.&quot;, &quot;$og_image_url&quot;:&quot;https://branch.io/img/logo_icon_black.png&quot;, &quot;$og_video&quot;:null, &quot;$og_type&quot;:null }</code></td></tr><tr><td><code>user_agent</code></td><td>End user&#39;s browser user agent string.</td><td><code>Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:73.0) Gecko/20100101 Firefox/73.0</code></td></tr><tr><td><code>title</code></td><td>The title of the web page where the Branch Web SDK was initialized. This title is hosted as part of the meta tags. Only gets returned if available.</td><td><code>title=&quot;Branch Metrics Web SDK Example App&quot;</code></td></tr><tr><td><code>description</code></td><td>The description of the web page where the Branch Web SDK was initialized. This title is hosted as part of the meta tags. Only gets returned if available.</td><td><code>description=&quot;A basic example of the Branch Web SDK.&quot;</code></td></tr></tbody></table><h2 id="browser-fingerprint-id" tabindex="-1">Browser fingerprint ID <a class="header-anchor" href="#browser-fingerprint-id" aria-label="Permalink to &quot;Browser fingerprint ID&quot;">​</a></h2><p>If you need to access your user&#39;s browser fingerprint ID for user deletion, use the <code>getBrowserFingerprintId()</code> method:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.getBrowserFingerprintId(function(err, data) { console.log(data); });</span></span></code></pre></div><p>Learn more about this method in our Web SDK Full Reference <a href="./web-full-reference.html#getbrowserfingerprintid">guide</a>.</p><h2 id="general-deep-linking" tabindex="-1">General deep linking <a class="header-anchor" href="#general-deep-linking" aria-label="Permalink to &quot;General deep linking&quot;">​</a></h2><p>Branch Deep Links are encapsulated with Deep Link properties, which get passed to Branch on a user&#39;s click.</p><h4 id="create-deep-links" tabindex="-1">Create deep links <a class="header-anchor" href="#create-deep-links" aria-label="Permalink to &quot;Create deep links&quot;">​</a></h4><p>Use the <code>link()</code> method to create a Branch Deep Link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var linkData = {</span></span>
<span class="line"><span>  campaign: &#39;content 123&#39;,</span></span>
<span class="line"><span>  channel: &#39;facebook&#39;,</span></span>
<span class="line"><span>  feature: &#39;dashboard&#39;,</span></span>
<span class="line"><span>  stage: &#39;new user&#39;,</span></span>
<span class="line"><span>  tags: [ &#39;tag1&#39;, &#39;tag2&#39;, &#39;tag3&#39; ],</span></span>
<span class="line"><span>  alias: &#39;&#39;,</span></span>
<span class="line"><span>  data: {</span></span>
<span class="line"><span>    &#39;custom_bool&#39;: true,</span></span>
<span class="line"><span>    &#39;custom_int&#39;: Date.now(),</span></span>
<span class="line"><span>    &#39;custom_string&#39;: &#39;hello&#39;,</span></span>
<span class="line"><span>    &#39;$og_title&#39;: &#39;Title&#39;,</span></span>
<span class="line"><span>    &#39;$og_description&#39;: &#39;Description&#39;,</span></span>
<span class="line"><span>    &#39;$og_image_url&#39;:&#39;http://lorempixel.com/400/400&#39;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.link(linkData, function(err, link) {</span></span>
<span class="line"><span>  console.log(link);</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>To test your Branch Deep Link configuration, follow our testing <a href="./web-testing.html#link-debugger">guide</a>.</p><h4 id="share-deep-links" tabindex="-1">Share deep links <a class="header-anchor" href="#share-deep-links" aria-label="Permalink to &quot;Share deep links&quot;">​</a></h4><p>Generate a Branch Deep Link encapsulated with Deep Link <a href="./creating-a-deep-link.html#create-deep-links">properties</a>, and tag it with the channel the user selects.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!-- shareable elements --&gt;</span></span>
<span class="line"><span>&lt;button id=&quot;button&quot;&gt;deep link&lt;/button&gt;</span></span>
<span class="line"><span>&lt;a id=&quot;anchor&quot; href=&quot;#&quot;&gt;deep link&lt;/a&gt;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var linkData = {</span></span>
<span class="line"><span>  campaign: &#39;content 123&#39;,</span></span>
<span class="line"><span>  channel: &#39;facebook&#39;,</span></span>
<span class="line"><span>  feature: &#39;dashboard&#39;,</span></span>
<span class="line"><span>  stage: &#39;new user&#39;,</span></span>
<span class="line"><span>  tags: [ &#39;tag1&#39;, &#39;tag2&#39;, &#39;tag3&#39; ],</span></span>
<span class="line"><span>  alias: &#39;&#39;,</span></span>
<span class="line"><span>  data: {</span></span>
<span class="line"><span>    &#39;custom_bool&#39;: true,</span></span>
<span class="line"><span>    &#39;custom_int&#39;: Date.now(),</span></span>
<span class="line"><span>    &#39;custom_string&#39;: &#39;hello&#39;,</span></span>
<span class="line"><span>    &#39;$og_title&#39;: &#39;Title&#39;,</span></span>
<span class="line"><span>    &#39;$og_description&#39;: &#39;Description&#39;,</span></span>
<span class="line"><span>    &#39;$og_image_url&#39;:&#39;http://lorempixel.com/400/400&#39;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.link(linkData, function(err, link) {</span></span>
<span class="line"><span>  // Bind elements</span></span>
<span class="line"><span>  document.getElementById(&#39;button&#39;).onclick = function() {</span></span>
<span class="line"><span>    window.open(link || err);</span></span>
<span class="line"><span>  };</span></span>
<span class="line"><span>  document.getElementById(&#39;anchor&#39;).href = link || err;</span></span>
<span class="line"><span>});</span></span></code></pre></div><h4 id="read-deep-link" tabindex="-1">Read deep link <a class="header-anchor" href="#read-deep-link" aria-label="Permalink to &quot;Read deep link&quot;">​</a></h4><p>You can read a Branch Deep Link to retrieve data from it. This must happen after Branch initialization.</p><p>The best practice is to get the data from the listener, since this will prevent a possible race condition.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// To read latest data, call \`data()\` method</span></span>
<span class="line"><span>branch.data(function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// To read first data, call \`first()\` method</span></span>
<span class="line"><span>branch.first(function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>To test reading a Branch Deep Link, follow our testing <a href="./web-testing.html#test-reading-deep-link">guide</a>.</p><h2 id="journeys" tabindex="-1">Journeys <a class="header-anchor" href="#journeys" aria-label="Permalink to &quot;Journeys&quot;">​</a></h2><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Access to the Journeys feature requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h4 id="journeys-assist" tabindex="-1">Journeys Assist <a class="header-anchor" href="#journeys-assist" aria-label="Permalink to &quot;Journeys Assist&quot;">​</a></h4><p>Branch&#39;s Journeys Assist feature combines powerful banners and interstitials from Journeys with the measurement capabilities of Ads, Email, and other Branch-powered channels.</p><p>This configuration provides you with complete attribution of the user flow.</p><h5 id="multi-session-assists" tabindex="-1">Multi session assists <a class="header-anchor" href="#multi-session-assists" aria-label="Permalink to &quot;Multi session assists&quot;">​</a></h5><p>For multi session assists, set the value of the <code>enableExtendedJourneysAssist</code> option to <code>true</code> and pass that to the Branch Web SDK during initialization:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var options = { </span></span>
<span class="line"><span>  enableExtendedJourneysAssist: true, // Enable referring Branch Link expiry for Journeys Assist</span></span>
<span class="line"><span>  extendedJourneysAssistExpiryTime : 5000 // TTL value in milliseconds for the referring Branch Link</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, options, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>Note that the value of the <code>extendedJourneysAssistExpiryTime</code> option defaults to 7 days.</p><p>For more details about Journeys Assist, visit our <a href="./journeys-assist.html">guide</a>.</p><h4 id="create-journeys-banner" tabindex="-1">Create Journeys Banner <a class="header-anchor" href="#create-journeys-banner" aria-label="Permalink to &quot;Create Journeys Banner&quot;">​</a></h4><p>A Branch Journeys Banner helps you convert mobile web users to app users.</p><p>To create a Journeys Banner:</p><ol><li><p>Create a new Journey on the <a href="https://dashboard.branch.io/journeys" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Validate that the Journey was created successfully by testing your website on a mobile device.</p></li><li><p>Append additional deep link data to the Journey button:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var linkData = {</span></span>
<span class="line"><span>  campaign: &#39;content 123&#39;,</span></span>
<span class="line"><span>  channel: &#39;facebook&#39;,</span></span>
<span class="line"><span>  feature: &#39;dashboard&#39;,</span></span>
<span class="line"><span>  stage: &#39;new user&#39;,</span></span>
<span class="line"><span>  tags: [ &#39;tag1&#39;, &#39;tag2&#39;, &#39;tag3&#39; ],</span></span>
<span class="line"><span>  alias: &#39;&#39;,</span></span>
<span class="line"><span>  data: {</span></span>
<span class="line"><span>    &#39;custom_bool&#39;: true,</span></span>
<span class="line"><span>    &#39;custom_int&#39;: Date.now(),</span></span>
<span class="line"><span>    &#39;custom_string&#39;: &#39;hello&#39;,</span></span>
<span class="line"><span>    &#39;$og_title&#39;: &#39;Title&#39;,</span></span>
<span class="line"><span>    &#39;$og_description&#39;: &#39;Description&#39;,</span></span>
<span class="line"><span>    &#39;$og_image_url&#39;:&#39;http://lorempixel.com/400/400&#39;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Set Branch Deep Link data dynamically for a given mobile web Journey</span></span>
<span class="line"><span>branch.setBranchViewData(linkData);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.closeJourney(function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.track(&quot;pageview&quot;);</span></span></code></pre></div></li></ol><h4 id="journeys-handle-listeners" tabindex="-1">Journeys handle listeners <a class="header-anchor" href="#journeys-handle-listeners" aria-label="Permalink to &quot;Journeys handle listeners&quot;">​</a></h4><p>You can use listeners to subscribe and unsubscribe from event streams related to Journeys.</p><h5 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Event key</th><th>Usage</th></tr></thead><tbody><tr><td><code>willShowJourney</code></td><td>Journey is about to be shown.</td></tr><tr><td><code>didShowJourney</code></td><td>Journey entrance animation is complete and is being shown to user.</td></tr><tr><td><code>willNotShowJourney</code></td><td>Journey will not be shown, and no other events will be emitted.</td></tr><tr><td><code>didClickJourneyCTA</code></td><td>User clicked on Journey&#39;s CTA button.</td></tr><tr><td><code>didClickJourneyClose</code></td><td>User clicked on Journey&#39;s close button.</td></tr><tr><td><code>willCloseJourney</code></td><td>Journey close animation has started.</td></tr><tr><td><code>didCloseJourney</code></td><td>Journey close animation is complete and Journey is no longer visible to user.</td></tr><tr><td><code>didCallJourneyClose</code></td><td>Emitted when developer calls <code>branch.closeJourney()</code> to dismiss Journey.</td></tr></tbody></table><h5 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h5><p>Subscribe to all events:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.addListener(listener);</span></span></code></pre></div><p>Subscribe to a single event, in this case <code>willShowJourney</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.addListener(&#39;willShowJourney&#39;, listener);</span></span></code></pre></div><p>Unsubscribe:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.removeListener(listener);</span></span></code></pre></div><h2 id="qr-codes" tabindex="-1">QR Codes <a class="header-anchor" href="#qr-codes" aria-label="Permalink to &quot;QR Codes&quot;">​</a></h2><p>Branch QR Codes contain a unique Branch Link, which you can use to navigate users to the correct content and for analytics tracking.</p><p>To create a Branch QR Code, you&#39;ll need to create two JavaScript objects: one for QR Code <a href="./qr-code-api.html">settings</a> and one for QR Code <a href="./creating-a-deep-link.html#create-deep-links">link params</a>.</p><p>Then, call the <code>qrCode()</code> method, passing in the two objects you just created, as well as a callback function that returns the actual QR Code.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$(&#39;#qrCode&#39;).click(function() {</span></span>
<span class="line"><span>	var qrCodeSettings = {</span></span>
<span class="line"><span>		&quot;code_color&quot;:&quot;#000000&quot;,</span></span>
<span class="line"><span>		&quot;background_color&quot;: &quot;#FFFFFF&quot;,</span></span>
<span class="line"><span>		&quot;margin&quot;: 5,</span></span>
<span class="line"><span>		&quot;width&quot;: 1000,</span></span>
<span class="line"><span>		&quot;image_format&quot;: &quot;png&quot;</span></span>
<span class="line"><span>	};</span></span>
<span class="line"><span>	var qrCodeParams = {</span></span>
<span class="line"><span>		tags: [ &#39;tag1&#39;, &#39;tag2&#39; ],</span></span>
<span class="line"><span>		channel: &#39;sample app&#39;,</span></span>
<span class="line"><span>		feature: &#39;create link&#39;,</span></span>
<span class="line"><span>		stage: &#39;created link&#39;,</span></span>
<span class="line"><span>		type: 1,</span></span>
<span class="line"><span>		data: {</span></span>
<span class="line"><span>			mydata: &#39;bar&#39;,</span></span>
<span class="line"><span>			&#39;$desktop_url&#39;: &#39;https://cdn.branch.io/example.html&#39;,</span></span>
<span class="line"><span>			&#39;$og_title&#39;: &#39;Branch Metrics&#39;,</span></span>
<span class="line"><span>			&#39;$og_description&#39;: &#39;Branch Metrics&#39;,</span></span>
<span class="line"><span>			&#39;$og_image_url&#39;: &#39;http://branch.io/img/logo_icon_white.png&#39;</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	};</span></span>
<span class="line"><span>	branch.qrCode(qrCodeParams, qrCodeSettings, function(err, qrCode) {</span></span>
<span class="line"><span>		response.html(&#39;&#39;);</span></span>
<span class="line"><span>	});</span></span>
<span class="line"><span>});</span></span></code></pre></div><h4 id="access-1" tabindex="-1">Access <a class="header-anchor" href="#access-1" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Basic Branch QR Codes are included in the free tier of the Branch Growth Platform. For more advanced QR Code capabilities, see our Engagement <a href="./packaging.html">product</a>.</p><h2 id="include-deep-link-data-in-html" tabindex="-1">Include deep link data in HTML <a class="header-anchor" href="#include-deep-link-data-in-html" aria-label="Permalink to &quot;Include deep link data in HTML&quot;">​</a></h2><p>Hosting data for Branch Links directly in your HTML gives Branch a way to scrape the page for that data and use it when creating a deep link. This makes it easier for marketers to create Branch Links.</p><p>This approach can be used for <a href="./journeys-overview.html">Journeys</a>, <a href="./branch-universal-email.html">Emails</a>, <a href="./create-quick-links.html">Short Links</a>, and the <a href="https://chromewebstore.google.com/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf?pli=1" target="_blank" rel="noreferrer">Chrome Extension</a>.</p><h4 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h4><ul><li>During link creation, provide Branch with a web URL to scrape. Branch will scrape the page for relevant data and include it in the deep link properties.</li><li>If you include link data in your website source code, Branch can automatically convert a simple web URL into a corresponding deep link that takes the user to relevant content in your app.</li><li>Branch will parse your Content Analytics data and provide you with more valuable information about which content is driving clicks, installs, opens, and in-app engagement.</li></ul><h4 id="important-considerations" tabindex="-1">Important considerations <a class="header-anchor" href="#important-considerations" aria-label="Permalink to &quot;Important considerations&quot;">​</a></h4><p>Please note that:</p><ul><li>Branch only scrapes web tags when a new link is created.</li><li>When Branch scrapes for this link data, no JavaScript will run on the page. Therefore, you will need to add the tags hosting the data directly to the HTML. This data should not be injected at page load via JavaScript or a tag manager.</li><li>The scraper will handle 30 redirects until it gets a <code>200</code> response.</li><li>The maximum number of redirected pages Branch will scrape data from is 8.</li></ul><h4 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h4><p>The first step to successfully including link data in your HTML is to understand how your deep links correspond to your web URLs. Ask yourself the following questions, and group your content accordingly:</p><ul><li><p>Do you have any content on web that doesn’t exist in the app?<br> Examples include: time-sensitive promotions, splash pages, micro-sites.</p></li><li><p>For content that has corresponding app content, what type of pages do you have?<br> Examples include: search result pages, category homepages, product pages.</p></li><li><p><strong>If</strong> you’ve already set up deep linking:</p><ul><li>What does your deep linking schema look like?</li><li>Do you use different keys for different content?</li><li>Do you have required key/value pairs that aren’t content specific?<br> Examples include: <code>productPage</code> or <code>categoryPage</code> keys, or <code>product_view=true</code>.</li></ul></li></ul><h4 id="examples-1" tabindex="-1">Examples <a class="header-anchor" href="#examples-1" aria-label="Permalink to &quot;Examples&quot;">​</a></h4><p>The examples below include the link data Branch should pick up, and the corresponding meta tags that need to be added to the web page for that to happen:</p><table tabindex="0"><thead><tr><th>Example URL</th><th>Example URL Data</th><th>Corresponding HTML Meta Tags</th></tr></thead><tbody><tr><td>&amp;lt;<a href="https://shop.com/shoes/brown-loafers%5C&amp;gt" target="_blank" rel="noreferrer">https://shop.com/shoes/brown-loafers\\&amp;gt</a>;</td><td><code>productId=1234</code>, <code>productView=true</code></td><td><code>&lt;meta name=&quot;branch:deeplink:productId&quot; content=&quot;1234&quot; /&gt;</code> <code>&lt;meta name=&quot;branch:deeplink:productView&quot; content=&quot;true&quot; /&gt;</code></td></tr><tr><td>&amp;lt;<a href="https://shop.com/shoes%5C&amp;gt" target="_blank" rel="noreferrer">https://shop.com/shoes\\&amp;gt</a>;</td><td><code>categoryId=5678</code></td><td><code>&lt;meta name=&quot;branch:deeplink:categoryId&quot; content=&quot;5678&quot; /&gt;</code></td></tr><tr><td>&amp;lt;<a href="https://shop.com/a-great-movie%5C&amp;gt" target="_blank" rel="noreferrer">https://shop.com/a-great-movie\\&amp;gt</a>;</td><td>No corresponding app content (<a href="./creating-a-deep-link.html#section-open-web-instead-of-app">open web</a>).</td><td><code>&lt;meta name=&quot;branch:deeplink:$web_only&quot; content=&quot;true&quot; /&gt;</code></td></tr></tbody></table><h4 id="validate" tabindex="-1">Validate <a class="header-anchor" href="#validate" aria-label="Permalink to &quot;Validate&quot;">​</a></h4><p>To validate that you are properly including link data in your HTML:</p><ol><li>Navigate to the Link Manager in the <a href="https://branch.dashboard.branch.io/quick-links/manager" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Click on the <strong>Create</strong> button to start creating a new Branch Short Link.</li><li>In the &quot;Original Web URL&quot; box, include the URL for your web page.</li></ol><h4 id="troubleshoot" tabindex="-1">Troubleshoot <a class="header-anchor" href="#troubleshoot" aria-label="Permalink to &quot;Troubleshoot&quot;">​</a></h4><p>If you find that Branch cannot scrape your web pages, you may need to put Branch&#39;s IP addresses on your allow list:</p><ul><li>52.9.159.121/32</li><li>52.9.176.205/32</li><li>52.9.188.221/32</li><li>52.9.188.236/32</li><li>44.247.175.42/32</li><li>35.160.5.60/32</li><li>44.238.95.201/32</li><li>35.163.128.27/32</li><li>52.34.127.49/32</li><li>44.247.58.38/32</li><li>44.231.103.124/32</li><li>100.21.145.61/32</li><li>35.167.148.222/32</li><li>44.237.121.167/32</li><li>52.33.75.0/32</li><li>52.43.119.253/32</li></ul><h2 id="set-custom-deep-link-path" tabindex="-1">Set custom deep link path <a class="header-anchor" href="#set-custom-deep-link-path" aria-label="Permalink to &quot;Set custom deep link path&quot;">​</a></h2><p>Branch automatically pulls meta tags for your convenience.</p><p>If canonical URL is set as a meta tag, it will become <code>$deeplink_path</code> in the Branch system by default.</p><p>However, you can override this default setting by manually setting <code>$deeplink_path</code> to the path your mobile app URL taxonomy uses for deep linking. This is done using the content field of the meta tag:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta name=&quot;branch:deeplink:$deeplink_path&quot; content=&quot;recipes/456789&quot; /&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, function(err, data) {</span></span>
<span class="line"><span>  if (document.querySelectorAll(&quot;meta[name=&#39;branch:deeplink:$deeplink_path&#39;]&quot;).length &gt; 0) {</span></span>
<span class="line"><span>    var meta = document.querySelector(&quot;meta[name=&#39;branch:deeplink:$deeplink_path&#39;]&quot;).getAttribute(&quot;content&quot;);</span></span>
<span class="line"><span>    branch.setBranchViewData({</span></span>
<span class="line"><span>      data:{</span></span>
<span class="line"><span>        &#39;$deeplink_path&#39;:meta</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    });</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>For more information on the <code>branch:deeplink:</code> keys you can use to customize your meta tags, please reference <a href="./deep-link-data-options.html">this table</a>.</p><h4 id="troubleshoot-1" tabindex="-1">Troubleshoot <a class="header-anchor" href="#troubleshoot-1" aria-label="Permalink to &quot;Troubleshoot&quot;">​</a></h4><ul><li>If you have <a href="https://developers.facebook.com/docs/applinks" target="_blank" rel="noreferrer">Facebook App Links meta tags</a> on your site that work with your app, then you can skip the instructions in this section. Branch will automatically fetch App Links tags and add them to your Branch Deep Link data.</li><li>Do not use Google Tag Manager (GTM) to insert your content meta tags. GTM requires JavaScript to load on the page, and the Branch data scraper does not support JavaScript execution.</li><li>If you need to allowlist the postback server IP addresses for security purposes, they are listed <a href="./basic-postback-configuration.html#allowlist-postback-ip-addresses">here</a>.</li></ul><h2 id="track-events" tabindex="-1">Track events <a class="header-anchor" href="#track-events" aria-label="Permalink to &quot;Track events&quot;">​</a></h2><p>By default, the Branch Web SDK tracks clicks, opens, installs, reinstalls, impressions, and Journeys dismissals automatically (out-of-the-box).</p><p>On web, an open is called a <code>web_session_start</code>. This event is triggered every time a webpage with the web SDK opens in a new tab, or when a user clicks on a Branch Link and is redirected to a page with the web SDK.</p><p>You can also <a href="./track-branch-events.html">track special user actions or application-specific events</a>. For example, you can track when a user adds an item to a shopping cart or searches for a keyword.</p><p>Learn more about <a href="./track-branch-events.html">tracking events</a> and the <code>logEvent()</code> <a href="./web-full-reference.html#logevent">method</a> in our guides.</p><h2 id="user-data" tabindex="-1">User data <a class="header-anchor" href="#user-data" aria-label="Permalink to &quot;User data&quot;">​</a></h2><h4 id="web-sdk-cookies" tabindex="-1">Web SDK cookies <a class="header-anchor" href="#web-sdk-cookies" aria-label="Permalink to &quot;Web SDK cookies&quot;">​</a></h4><p>The table in this section describes the types of cookies set by Branch’s web SDK when implemented on a customer’s website.</p><table tabindex="0"><thead><tr><th><strong>Name</strong></th><th><strong>Type</strong></th><th><strong>Description</strong></th><th><strong>Expiry</strong></th><th><strong>Notes</strong></th></tr></thead><tbody><tr><td><code>_s</code></td><td>Third-party cookie</td><td>This cookie is tied to initialization of the Web SDK on customers&#39; websites. It is used for Journeys targeting and analytics.</td><td>6 months and refreshed on activity</td><td>Cookie is encrypted and secure (only transmitted over SSL).</td></tr><tr><td><code>branch_session</code></td><td>Session storage</td><td>Contains data for deep linking, personalization, and analytics for customers running the Web SDK.</td><td>Gets cleared when the browser tab or window is closed.</td><td>This is considered first-party because the Web SDK is running as part of the customer&#39;s website.</td></tr><tr><td><code>branch_session_first</code></td><td>Local storage</td><td>Contains data for deep linking, personalization, and analytics for customers running the Web SDK.</td><td>Data is stored indefinitely until explicitly cleared which the web site developer can do directly.</td><td>This is considered first-party because the Web SDK is running as part of the customer&#39;s website.</td></tr></tbody></table><h4 id="google-dma-compliance" tabindex="-1">Google DMA compliance <a class="header-anchor" href="#google-dma-compliance" aria-label="Permalink to &quot;Google DMA compliance&quot;">​</a></h4><p>In response to the European Union&#39;s enactment of the Digital Markets Act (DMA), the Branch iOS SDK includes the <code>setDMAParamsForEEA()</code> method to help you pass consent information from your user to Google.</p><p>The <code>setDMAParamsForEEA()</code> method takes 3 parameters:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>eeaRegion</code></td><td><code>Boolean</code></td><td>Set to <code>true</code> if user is <strong>included</strong> in European Union regulations. For example, if the user is located within the EEA, they are within the scope of DMA. Set to <code>false</code> if user is considered <strong>excluded</strong> from European Union regulations.</td><td><strong>Required</strong> if EU regulations apply to this user</td></tr><tr><td><code>adPersonalizationConsent</code></td><td><code>Boolean</code></td><td>Set to <code>true</code> if user has <strong>granted</strong> consent for ads personalization. Set to <code>false</code> if user has <strong>denied</strong> consent for ads personalization.</td><td><strong>Required</strong> if <code>eeaRegion</code> is set to <code>true</code> (i.e., EU regulations apply to this user)</td></tr><tr><td><code>adUserDataUsageConsent</code></td><td><code>Boolean</code></td><td>Set to <code>true</code> if user has <strong>granted</strong> consent for 3P transmission of user-level data for ads. Set to <code>false</code> is user has <strong>denied</strong> consent for 3P transmission of user-level data for ads.</td><td><strong>Required</strong> if <code>eeaRegion</code> is set to <code>true</code> (i.e., EU regulations apply to this user)</td></tr></tbody></table><h5 id="default-behavior" tabindex="-1">Default behavior <a class="header-anchor" href="#default-behavior" aria-label="Permalink to &quot;Default behavior&quot;">​</a></h5><p>When <code>eeaRegion</code> is set to <code>true</code>, the parameters <code>adPersonalizationConsent</code> and <code>adUserDataUsageConsent</code> must also be set.</p><p>When parameters are successfully set using <code>setDMAParamsForEEA()</code>, they will be sent along with every future request to the following Branch endpoints:</p><ul><li><code>/v1/install</code></li><li><code>/v1/open</code></li><li><code>/v2/event</code></li></ul><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that the 3 parameters passed to <code>setDMAParamsForEEA()</code> are all <code>false</code> by default.</p><p><strong>Failure to include user consent signals may result in attribution or campaign performance degradation. For additional information, please reach out to your Google AM.</strong></p></div><h5 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h5><p>The <code>setDMAParamsForEEA()</code> method can be called before or after the <code>init()</code> method, and will be queued accordingly:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Example for an EEA resident who has denied both ad personalization and data usage consent</span></span>
<span class="line"><span>branch.setDMAParamsForEEA(true,false,false);</span></span></code></pre></div><h4 id="set-user-identity" tabindex="-1">Set user identity <a class="header-anchor" href="#set-user-identity" aria-label="Permalink to &quot;Set user identity&quot;">​</a></h4><p>An &quot;identity&quot; is a unique alias attributed to a specific user in the Branch system.</p><p>Some scenarios which could leverage the <code>setIdentity()</code> function:</p><ul><li>You have your own user IDs that you want to see reflected in the Branch system.</li><li>You want referral and event data to persist across platforms so you can see how your users access your service from different devices.</li><li>You want referral and event data to persist across uninstall/reinstall events.</li></ul><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Do not send any PII through the <code>setIdentity()</code> method. For additional details, please view our guide on <a href="./best-practices-to-avoid-sending-pii-to-branch.html">Best Practices to Avoid Sending PII to Branch</a>.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Login and set user identity</span></span>
<span class="line"><span>branch.setIdentity(&#39;123456&#39;, function (err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Logout</span></span>
<span class="line"><span>branch.logout(function(err, data) {</span></span>
<span class="line"><span>	console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>To confirm that user identities are being set as expected, use the <a href="https://dashboard.branch.io/liveview?_gl=1*lyl2am*_ga*MTE0ODc2MjU5OC4xNjc5MzM4OTI0*_ga_KSDD8Y11CT*MTcxNTgwNjI3MS41NDMuMS4xNzE1ODA2NzQ2LjYwLjAuMA.." target="_blank" rel="noreferrer">Liveview</a> section of the Branch Dashboard.</p><h4 id="disable-tracking" tabindex="-1">Disable tracking <a class="header-anchor" href="#disable-tracking" aria-label="Permalink to &quot;Disable tracking&quot;">​</a></h4><p>To disable tracking across your entire website, set the <code>tracking_disabled</code> flag to <code>true</code> and pass that to the <code>init()</code> method during Branch initialization:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.init( &#39;BRANCH_KEY&#39;, {‘tracking_disabled’ : true});</span></span></code></pre></div><p>If you want to disable tracking <strong>after</strong> initialization, call the <code>disableTracking()</code> function. Calling this function, either with the parameter <code>true</code> or no parameters, will disable tracking.</p>`,120)])])}const b=a(o,[["render",i]]);export{u as __pageData,b as default};
